public int minOperations(int[] nums) {
    int operations = 0;
    for (int i = 1; i < nums.length; i++) {
        if (nums[i] <= nums[i - 1]) {
            int diff = nums[i - 1] - nums[i] + 1;
            operations += Math.ceil(Math.log(diff) / Math.log(2));
            nums[i] += diff;
        }
    }
    return operations;
}
```

